changeSet.sql:
CREATE INDEX IF NOT EXISTS idx_chat_participant_one
    ON chat (participant_one);
CREATE INDEX IF NOT EXISTS idx_chat_participant_two
    ON chat (participant_two);
CREATE INDEX IF NOT EXISTS idx_chat_last_message_at
    ON chat (participant_one, last_message_at DESC);
CREATE INDEX IF NOT EXISTS idx_chat_listing
    ON chat (listing_id) WHERE listing_id IS NOT NULL;
